(()=>{
'use strict';
if(!window.__ADMIN_PERF_ACTIVE_V2_LOADER__){window.__ADMIN_PERF_ACTIVE_V2_LOADER__=true;document.write('<script src="/assets/admin-performance-active-v2.js?v=1"><\/script>')}
const DEFAULT_URL='https://saodmeoilixfdqentofp.supabase.co';
const BUCKET='doit-files';
const PREFIXES=['performance','uploads','raw','parsed','team'];
const PERF_DAYS=30,RAW_DAYS=7,KEEP_REVISIONS=3;
const $=s=>document.querySelector(s);
const selected=new Set();
let files=[],active=null,modalFilter='all';
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const n=v=>Number(v||0)||0;
const size=v=>{v=n(v);if(!v)return'—';const u=['B','KB','MB','GB'];let i=0;while(v>=1024&&i<u.length-1){v/=1024;i++}return(i?v.toFixed(2):Math.round(v))+' '+u[i]};
const dateOf=v=>{const s=String(v||''),m=s.match(/(20\d{2}-\d{2}-\d{2})/);if(m)return m[1];const d=new Date(s);return Number.isNaN(d.getTime())?'':d.toISOString().slice(0,10)};
const isPerf=p=>/^performance\//i.test(String(p||''));
const isDoit=p=>/^(uploads|raw|parsed)\//i.test(String(p||''));
const isTeam=p=>/^team\//i.test(String(p||''));
const isSystem=p=>/^performance\/(active|index)\.json$/i.test(String(p||''));
const isPerfJson=p=>/^performance\//i.test(p)&&/\.json$/i.test(p);
const isPerfRaw=p=>/^performance\//i.test(p)&&(/\.(xlsx|xlsm|xls|csv)$/i.test(p));
function log(v){const box=$('#storageStatus');if(box)box.textContent=typeof v==='string'?v:JSON.stringify(v,null,2)}
function cfg(){let saved={};try{saved=JSON.parse(localStorage.getItem('doit-cloud-cfg')||'{}')}catch{}const url=String($('#sbUrl')?.value||saved.url||DEFAULT_URL).trim().replace(/\/$/,'');const key=String($('#sbKey')?.value||saved.key||'').trim();return{url,key}}
function headers(extra={}){const c=cfg();return{apikey:c.key,authorization:'Bearer '+c.key,...extra}}
async function req(path,opt={}){const c=cfg();if(!c.key)throw{ok:false,error:'missing_key',note:'ต้องกรอก Supabase key ก่อน'};const r=await fetch(c.url+path,{...opt,headers:headers(opt.headers||{})}),t=await r.text();let data;try{data=JSON.parse(t)}catch{data={raw:t}}if(!r.ok)throw data;return data}
async function readJson(path){return req('/storage/v1/object/'+BUCKET+'/'+encodeURIComponent(path).replace(/%2F/g,'/'))}
async function deleteObject(path){return req('/storage/v1/object/'+BUCKET+'/'+encodeURIComponent(path).replace(/%2F/g,'/'),{method:'DELETE'})}
async function listPrefix(prefix){try{const rows=await req('/storage/v1/object/list/'+BUCKET,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({prefix,limit:1000,offset:0,sortBy:{column:'updated_at',order:'desc'}})});return(Array.isArray(rows)?rows:[]).map(x=>{const name=String(x.name||''),path=name.startsWith(prefix+'/')?name:prefix+'/'+name,created=x.updated_at||x.created_at||'';return{path,name,size:n(x.metadata?.size||x.size),created_at:created,date:dateOf(path)||dateOf(created)}}).filter(x=>x.name&&!/\/$/.test(x.name))}catch{return[]}}
function protectedSet(){const p=new Set(['performance/active.json','performance/index.json']);const add=v=>{if(v)p.add(String(v).replace(/^\/+/,''))};add(active?.dataPath);add(active?.currentDataPath);add(active?.latestPath);add(active?.previousDataPath);add(active?.prevDataPath);add(active?.current?.dataPath);add(active?.previous?.dataPath);(active?.history||[]).slice(0,2).forEach(x=>add(x?.dataPath||x?.latestPath||x?.path));const latest=new Map();files.filter(f=>isPerfJson(f.path)&&!isSystem(f.path)&&f.date).forEach(f=>{const old=latest.get(f.date);if(!old||String(f.created_at||f.path)>String(old.created_at||old.path))latest.set(f.date,f)});[...latest.entries()].sort((a,b)=>b[0].localeCompare(a[0])).slice(0,PERF_DAYS).forEach(([,f])=>add(f.path));return p}
function typeOf(f){const ps=protectedSet();if(ps.has(f.path)||isSystem(f.path))return{type:'protected',label:'กันลบ'};if(isDoit(f.path))return{type:'doit',label:'DOIT'};if(isPerf(f.path))return{type:'performance',label:isPerfJson(f.path)?'Performance JSON':'Performance'};if(isTeam(f.path))return{type:'team',label:'Team'};return{type:'other',label:'Other'}}
function cleanupCandidates(){const now=new Date(),pc=new Date(now),rc=new Date(now),out=[];pc.setDate(now.getDate()-PERF_DAYS);rc.setDate(now.getDate()-RAW_DAYS);const add=(f,reason)=>{if(typeOf(f).type==='performance')out.push({...f,reason})};files.forEach(f=>{const d=f.date?new Date(f.date):(f.created_at?new Date(f.created_at):null);if(isPerfJson(f.path)&&d&&d<pc)add(f,'JSON เกิน '+PERF_DAYS+' วัน');if(isPerfRaw(f.path)&&d&&d<rc)add(f,'RAW Performance เกิน '+RAW_DAYS+' วัน')});const byDay=new Map();files.filter(f=>isPerfJson(f.path)&&!isSystem(f.path)&&f.date).forEach(f=>{if(!byDay.has(f.date))byDay.set(f.date,[]);byDay.get(f.date).push(f)});byDay.forEach(list=>{list.sort((a,b)=>String(b.created_at||b.path).localeCompare(String(a.created_at||a.path)));list.slice(KEEP_REVISIONS+1).forEach(f=>add(f,'revision เกิน '+KEEP_REVISIONS+' ไฟล์/วัน'))});return out}
function canSelect(f){return typeOf(f).type!=='protected'}
function match(f,q){q=String(q||'').toLowerCase();const t=typeOf(f).type,c=cleanupCandidates().some(x=>x.path===f.path);const ok=modalFilter==='all'||(modalFilter==='cleanup'&&c)||(modalFilter==='doit'&&t==='doit')||(modalFilter==='protected'&&t==='protected')||(modalFilter==='selectable'&&canSelect(f))||(modalFilter==='json'&&isPerfJson(f.path))||(modalFilter==='team'&&t==='team');return ok&&(!q||f.path.toLowerCase().includes(q)||String(f.date).includes(q))}
function render(){const body=$('#storageFiles');if(!body)return;const q=$('#storageFilter')?.value||'';const rows=files.filter(f=>match(f,q)).slice(0,500);body.innerHTML=rows.map(f=>{const t=typeOf(f),can=canSelect(f);return`<tr><td><input class="storagePick" type="checkbox" data-path="${esc(f.path)}" ${selected.has(f.path)?'checked':''} ${can?'':'disabled'}></td><td>${esc(t.label)}${can?' · เลือกได้':' · ล็อก'}</td><td>${esc(f.path)}</td><td>${size(f.size)}</td><td>${esc(f.date||f.created_at||'')}</td><td>${esc(t.type)}</td><td><button class="btn2 storageDownload" data-path="${esc(f.path)}">โหลด</button></td></tr>`}).join('')||'<tr><td colspan="7" class="muted">ไม่พบไฟล์</td></tr>';document.querySelectorAll('.storagePick').forEach(x=>x.onchange=e=>{if(e.target.checked)selected.add(e.target.dataset.path);else selected.delete(e.target.dataset.path)});document.querySelectorAll('.storageDownload').forEach(x=>x.onclick=()=>download(x.dataset.path));}
async function refresh(){try{log('กำลังโหลด Storage...');try{active=await readJson('performance/active.json')}catch{active=null}const lists=await Promise.all(PREFIXES.map(listPrefix));files=lists.flat().sort((a,b)=>String(b.created_at||b.path).localeCompare(String(a.created_at||a.path)));selected.clear();$('#storageCount').textContent=files.length.toLocaleString('th-TH');$('#storageSize').textContent=size(files.reduce((s,f)=>s+n(f.size),0));$('#storageLatest').textContent=files[0]?.date||'—';$('#storageActive').textContent=active?.reportDate||active?.versionId||'—';render();log({ok:true,real_delete_enabled_for_all_unprotected:true,protected:[...protectedSet()].slice(0,200),types:{protected:files.filter(f=>typeOf(f).type==='protected').length,doit:files.filter(f=>typeOf(f).type==='doit').length,performance:files.filter(f=>typeOf(f).type==='performance').length,team:files.filter(f=>typeOf(f).type==='team').length,other:files.filter(f=>typeOf(f).type==='other').length},files:files.length,cleanup_candidates:cleanupCandidates().length})}catch(e){log(e)}}
function previewOld(){selected.clear();cleanupCandidates().forEach(f=>selected.add(f.path));modalFilter='cleanup';render();log({ok:true,dry_run:true,selected:[...selected].slice(0,200),note:'Preview ไฟล์ Performance เก่าที่ลบได้จริงหลังพิมพ์ DELETE'})}
function confirmDelete(){return String($('#storageConfirm')?.value||'').trim().toUpperCase()==='DELETE'}
async function deletePaths(paths,label='ไฟล์ที่เลือก'){try{const picked=paths.map(p=>files.find(f=>f.path===p)||{path:p}).filter(f=>typeOf(f).type!=='protected');if(!picked.length)return log({ok:false,error:'no_deletable_file_selected',note:'ไม่มีไฟล์ที่ลบได้ในรายการนี้'});if(!confirmDelete())return log({ok:false,error:'confirm_required',note:'พิมพ์ DELETE ในช่องยืนยันก่อนลบ',selected:picked.map(f=>f.path).slice(0,200)});log('กำลังลบ '+label+' '+picked.length+' ไฟล์...');const done=[],fail=[];for(const f of picked){try{await deleteObject(f.path);done.push(f.path)}catch(e){fail.push({path:f.path,error:e})}}selected.clear();await refresh();log({ok:!fail.length,deleted_count:done.length,deleted:done,failed:fail,note:'ลบผ่าน Supabase Storage DELETE แล้ว ไฟล์ที่สำเร็จจะหายจริงจาก bucket'})}catch(e){log(e)}}
function deleteSelected(){return deletePaths([...selected],'ไฟล์ที่เลือก')}
function deleteOld(){return deletePaths(cleanupCandidates().map(f=>f.path),'ไฟล์เก่า')}
async function download(path){try{const c=cfg();const r=await fetch(`${c.url}/storage/v1/object/${BUCKET}/${encodeURIComponent(path).replace(/%2F/g,'/')}`,{headers:headers()});if(!r.ok)throw await r.text();const b=await r.blob(),a=document.createElement('a');a.href=URL.createObjectURL(b);a.download=path.split('/').pop()||'file';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1500)}catch(e){log(e)}}
function init(){if(!$('#adminStoragePanel'))return;const hint=$('#adminStoragePanel .safeBox');if(hint)hint.innerHTML='<b>โหมดลบจริง</b><br>ลบจริงได้ทุกไฟล์ที่ไม่ถูกกันลบ: DOIT / Performance เก่า / Team / Other · ต้องพิมพ์ DELETE ยืนยัน · active/latest/system ยังล็อก';$('#storageRefresh').onclick=refresh;$('#storageFilter').oninput=render;$('#storagePreviewOld').onclick=previewOld;$('#storageDeleteOld').onclick=deleteOld;$('#storageDeleteSelected').onclick=deleteSelected;$('#storageCheckAll').onchange=e=>{selected.clear();if(e.target.checked)files.filter(canSelect).forEach(f=>selected.add(f.path));render()};setTimeout(refresh,500)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);else init();
})();